import { useState } from "react";
import TabBar           from "./TabBar";
import AudioCallTab     from "./AudioCallTab";
import RoleplayTab      from "./RoleplayTab";
import ApiKeyInput      from "./ApiKeyInput";
import LanguageSelector from "./LanguageSelector";
import "./AriaWidget.css";

export default function AriaWidget({ topic = "General" }) {
  const [activeTab, setActiveTab] = useState("audio");
  const [apiKey,    setApiKey]    = useState("");
  const [language,  setLanguage]  = useState(null);

  // Gate 1 — API key
  if (!apiKey) {
    return (
      <div className="aria-widget">
        <div className="aria-header">
          <span className="aria-logo">🌐 Aria</span>
          <span className="aria-topic-pill">{topic}</span>
        </div>
        <ApiKeyInput onKeySubmit={(key) => setApiKey(key)} />
      </div>
    );
  }

  // Gate 2 — Language selection
  if (!language) {
    return (
      <div className="aria-widget">
        <div className="aria-header">
          <span className="aria-logo">🌐 Aria</span>
          <span className="aria-topic-pill">{topic}</span>
        </div>
        <LanguageSelector onSelect={(lang) => setLanguage(lang)} />
      </div>
    );
  }

  // Main widget — both gates passed
  return (
    <div className="aria-widget">
      <div className="aria-header">
        <span className="aria-logo">🌐 Aria</span>
        <span className="aria-topic-pill">{topic}</span>
        <div className="aria-header-right">
          <span className="aria-lang-badge">
            {language.flag} {language.name}
          </span>
          <button
            className="aria-key-reset"
            title="Reset"
            onClick={() => { setApiKey(""); setLanguage(null); }}
          >
            🔄
          </button>
        </div>
      </div>
      <TabBar activeTab={activeTab} setActiveTab={setActiveTab} />
      <div className="aria-tab-content">
        {activeTab === "audio"  && <AudioCallTab topic={topic} apiKey={apiKey} language={language} />}
        {activeTab === "quests" && <RoleplayTab  topic={topic} apiKey={apiKey} language={language} />}
      </div>
    </div>
  );
}
